1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty array for single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should return empty array for two live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has exactly 2 live neighbors (survival)", () => {
15	    // A column of 3 live cells: [(0,0),(0,1),(0,2)] - center (0,1) has exactly 2 live neighbors
16	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
17	    expect(result).toContainEqual([0, 1]);
18	    expect(result).not.toContainEqual([0, 0]);
19	    expect(result).not.toContainEqual([0, 2]);
20	  });
21	  it("should keep a live cell alive when it has exactly 3 live neighbors (survival)", () => {
22	    // [(0,0), (1,0), (2,0), (1,1)] - cell (1,0) has neighbors (0,0),(2,0),(1,1) = 3 live neighbors, should survive
23	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
24	    expect(result).toContainEqual([1, 0]);
25	  });
26	  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
27	  it.todo("should make a dead cell with exactly 3 live neighbors become alive (reproduction)");
28	  it.todo("should produce correct next generation for a blinker oscillator");
29	  it.todo("should produce correct next generation for a block still life");
30	});
