1	type Cell = [number, number];
2	
3	const countLiveNeighbors = (cell: Cell, cells: Cell[]): number => {
4	  const [x, y] = cell;
5	  return cells.filter(([cx, cy]) =>
6	    Math.abs(cx - x) <= 1 && Math.abs(cy - y) <= 1 && (cx !== x || cy !== y)
7	  ).length;
8	};
9	
10	export function nextGeneration(cells: Cell[]): Cell[] {
11	  return cells.filter((cell) => {
12	    const neighbors = countLiveNeighbors(cell, cells);
13	    return neighbors === 2 || neighbors === 3;
14	  });
15	}
